function networkBecomesIdle(edges, patience) {
    const n = patience.length;
    const graph = new Array(n).fill(null).map(() => []);

    for (const edge of edges) {
        graph[edge[0]].push(edge[1]);
        graph[edge[1]].push(edge[0]);
    }

    const dist = new Array(n).fill(-1);
    dist[0] = 0;
    const q = [0];

    while (q.length > 0) {
        const node = q.shift();

        for (const neighbor of graph[node]) {
            if (dist[neighbor] === -1) {
                dist[neighbor] = dist[node] + 1;
                q.push(neighbor);
            }
        }
    }

    let max_time = 0;
    for (let i = 1; i < n; i++) {
        const time = Math.floor((2 * dist[i] - 1) / patience[i]) * patience[i] + 2 * dist[i];
        max_time = Math.max(max_time, time);
    }

    return max_time + 1;
}
```

    1. Build a graph with the given edges.
2. Use BFS to calculate the shortest distance from server 0 to each other server.
3. For each data server, calculate the time it takes for the messages to be sent and replied (use patience to compute the message waiting time).
4. Find the maximum time among all data servers.
5. Return the maximum time + 1 as the earliest second the network becomes idle.

