    ```java
import java.util.*;

class Solution {
    public int networkBecomesIdle(int[][] edges, int[] patience) {
        int n = patience.length;
        List<List<Integer>> graph = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }

        for (int[] edge : edges) {
            graph.get(edge[0]).add(edge[1]);
            graph.get(edge[1]).add(edge[0]);
        }

        int[] dist = new int[n];
        Arrays.fill(dist, -1);
        dist[0] = 0;
        Queue<Integer> q = new LinkedList<>();
        q.add(0);

        while (!q.isEmpty()) {
            int node = q.poll();

            for (int neighbor : graph.get(node)) {
                if (dist[neighbor] == -1) {
                    dist[neighbor] = dist[node] + 1;
                    q.add(neighbor);
                }
            }
        }

        int max_time = 0;
        for (int i = 1; i < n; i++) {
            int time = ((2 * dist[i] - 1) / patience[i]) * patience[i] + 2 * dist[i];
            max_time = Math.max(max_time, time);
        }

        return max_time + 1;
    }
}
```

    1. Build a graph with the given edges.
2. Use BFS to calculate the shortest distance from server 0 to each other server.
3. For each data server, calculate the time it takes for the messages to be sent and replied (use patience to compute the message waiting time).
4. Find the maximum time among all data servers.
5. Return the maximum time + 1 as the earliest second the network becomes idle.
